import React from 'react';
import Header from './components/Header';
import QuizBuilder from './components/QuizBuilder';
import HeroSection from './components/HeroSection';

function App() {
  return (
    <>
      <Header />
      <HeroSection />
      <div className="app-container">
        <QuizBuilder />
      </div>
    </>
  );
}

export default App;
